"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[6236],{25489:e=>{e.exports=JSON.parse('{"functions":[{"name":"TimeThreshold","desc":"Minimum time in seconds that must elapse between successive bounces.\\nTwo bounces closer together than this are flagged as a corner trap (Pass 1).\\n\\nDefault: `0.002`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"CornerTrapBuilder"}],"function_type":"method","source":{"line":575,"path":"docs/SubBuilders.lua"}},{"name":"PositionHistorySize","desc":"Number of bounce contact points kept in the rolling position history.\\nMust be a positive integer. Higher values make the Pass 3 spatial and\\nPass 4 progress checks more robust at the cost of slightly more memory.\\n\\nDefault: `4`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"CornerTrapBuilder"}],"function_type":"method","source":{"line":587,"path":"docs/SubBuilders.lua"}},{"name":"DisplacementThreshold","desc":"Minimum stud distance between successive bounce contact points.\\nDisplacement below this threshold triggers the Pass 3 spatial-proximity guard.\\n\\nDefault: `0.5`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"CornerTrapBuilder"}],"function_type":"method","source":{"line":598,"path":"docs/SubBuilders.lua"}},{"name":"EMAAlpha","desc":"EMA smoothing factor for velocity direction tracking (Pass 2). Must be in `(0, 1)`.\\nHigher values weight recent bounces more heavily \u2014 detection is faster but more\\nsensitive to brief directional wobble.\\n\\nDefault: `0.4`\\n\\n:::caution\\n`CornerEMAThreshold` must be `> |1 \u2212 2 \xb7 CornerEMAAlpha|`. If you change\\nthis value, adjust `EMAThreshold` accordingly. `:Build()` enforces this.\\n:::","params":[{"name":"value","desc":"Must be in (0, 1).","lua_type":"number"}],"returns":[{"desc":"","lua_type":"CornerTrapBuilder"}],"function_type":"method","source":{"line":615,"path":"docs/SubBuilders.lua"}},{"name":"EMAThreshold","desc":"EMA magnitude threshold below which oscillation is declared (Pass 2).\\nMust be `> |1 \u2212 2 \xb7 CornerEMAAlpha|` \u2014 see class note.\\n\\nDefault: `0.25`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"CornerTrapBuilder"}],"function_type":"method","source":{"line":626,"path":"docs/SubBuilders.lua"}},{"name":"MinProgressPerBounce","desc":"Minimum studs the bullet must advance from its first bounce contact over\\nthe `PositionHistorySize` window (Pass 4). Set to `0` to disable Pass 4.\\n\\nDefault: `0.3`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"CornerTrapBuilder"}],"function_type":"method","source":{"line":637,"path":"docs/SubBuilders.lua"}},{"name":"Done","desc":"Returns the root [BehaviorBuilder].","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"method","source":{"line":644,"path":"docs/SubBuilders.lua"}}],"properties":[],"types":[],"name":"CornerTrapBuilder","desc":"Sub-builder for corner-trap detection configuration. Opened via\\n[BehaviorBuilder:CornerTrap]. Call `:Done()` to return to the root\\n[BehaviorBuilder].\\n\\nCorner-trap detection terminates bullets that become stuck bouncing\\ninfinitely between two or more opposing surfaces (V-grooves, inside corners,\\nnarrow slots). The detector runs four independent checks \u2014 any single check\\nfiring is sufficient to declare a trap and terminate the cast:\\n\\n**Pass 1 \u2014 Temporal:** Two bounces within `CornerTimeThreshold` seconds\\ntriggers termination.\\n\\n**Pass 2 \u2014 Velocity EMA:** An exponential moving average of the bullet\'s\\nvelocity direction is tracked across bounces. If the EMA magnitude falls\\nbelow `CornerEMAThreshold`, the bullet is oscillating and is terminated.\\n\\n**Pass 3 \u2014 Spatial:** If successive bounce contact points fall within\\n`CornerDisplacementThreshold` studs of each other, the bullet is trapped.\\n\\n**Pass 4 \u2014 Minimum progress:** The bullet must advance at least\\n`CornerMinProgressPerBounce` studs from its first bounce contact over\\nthe tracked history window. Catches slow-drift traps that pass the other\\nthree checks. Set to `0` to disable this pass.\\n\\n:::tip EMA parameter constraint\\n`CornerEMAThreshold` must be greater than `|1 \u2212 2 \xb7 CornerEMAAlpha|`.\\nAt the default `alpha = 0.4`, this gives `|1 - 0.8| = 0.2`, so the\\nthreshold must be `> 0.2`. The default `0.25` satisfies this with a\\nclear margin. `:Build()` validates this constraint and returns `nil`\\nif it is violated.\\n:::","source":{"line":564,"path":"docs/SubBuilders.lua"}}')}}]);